import './App.css';
import Hero from './components/Hero';
import Gallery from './components/Gallery';
import { menu } from './menu';
import { useRef } from 'react';

function App(): JSX.Element {
  const menuRef = useRef(null)

  return (
    <div className="app">
      <Hero ref={menuRef}/>
      {menu.map((section) => (
        <div ref = {section.title == "Ramen" ? menuRef: null}>
          <Gallery
            key={section.title}
            title={section.title}
            items={section.items}
          />
        </div>
      ))}
    </div>
  );
}

export default App;
